    int imgWidth = 1664;
    int imgHeight = 448;
    int width = 512;
    int height = 128;

    for (size_t k = 0; k < allProcessedData.size(); ++k) {
        TCanvas canvas("c", "Canvas", imgWidth, imgHeight);
        TH2D histogram("h2", "Matrix Plot", width, 0, width, height, 0, height);

        for (int i = 0; i < height; ++i) {
            for (int j = 0; j < width; ++j) {
                histogram.SetBinContent(j + 1, i + 1, allProcessedData[k][i * width + j]);
            }
        }

        gStyle->SetPalette(kRainBow);
        histogram.Draw("COLZ");

        canvas.SaveAs(Form("output_image_%d.png", k));
        std::cout << "Saved image: output_image_" << k << ".png" << std::endl;
    }
}

int main(int argc, char* argv[]) {
    TApplication app("App", &argc, argv);

    // 假设有nRows行数据需要处理
    int nRows = 4086;
    std::vector<std::vector<double>> data(nRows, std::vector<double>(65536, 0)); // 模拟输入数据
    std::vector<std::vector<double>> processedData(nRows);

    std::vector<std::thread> workers;
    for (int i = 0; i < nRows; ++i) {
        workers.emplace_back(processRow, std::ref(data[i]), std::ref(processedData[i]));
    }

    for (auto& worker : workers) {
